//  Bug: all closures share ONE var 'i' — by loop end, i === 3
const fns = [];
for (var i = 0; i < 3; i++) {
  fns.push(() => console.log(i)); // all capture the SAME 'i' binding
}
fns.forEach(f => f()); // 3, 3, 3 — not 0, 1, 2!

//  Fix: 'let' creates a NEW binding per iteration
const fnsFixed = [];
for (let j = 0; j < 3; j++) {
  fnsFixed.push(() => console.log(j)); // each closure captures its OWN 'j'
}
fnsFixed.forEach(f => f()); // 0, 1, 2 

// Why? 'let' in a for-loop creates a fresh Lexical Environment
// (and a new 'j' binding) for every iteration.

