function setup() {
  const bigData = new Array(1_000_000).fill('leak risk');

  return function cleanup() {
    // bigData is captured — it stays in memory as long as 'cleanup' is referenced
    console.log('cleaning up...');
  };
}

const cleanupFn = setup(); // bigData now lives in heap indefinitely
// ... some time later:
cleanupFn(); // do the work
cleanupFn = null; //  release the closure — bigData can now be GC'd
